import { useEffect, useRef } from 'react'
import { gsap, Power3 } from 'gsap'
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { useMediaQuery } from 'usehooks-ts';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

import './HomeProjects.css'

import privateImg from '../../assets/projects/private.png'
import publicImg from '../../assets/projects/public.png'
import arrow from '../../assets/icons/arrowhead-up.png'

function HomeProjects(props){
    const privateImgRef = useRef(null)
    const publicImgRef = useRef(null)
    const mobile = useMediaQuery('(max-width: 480px)')
    const { t } = useTranslation();

    useEffect(()=>{
        if(props.animate && !mobile){
            gsap.registerPlugin(ScrollTrigger) 

            gsap.fromTo(privateImgRef.current,{
                scale:0.8,
                opacity:0.7
            },{
                scale:1,
                opacity:1,
                scrollTrigger:{
                    trigger:privateImgRef.current,
                    start:"top 75%",
                    end: "top 35%",
                    scrub:true,
                },
                ease: Power3.easeInOut
            })
            gsap.fromTo(publicImgRef.current,{
                scale:0.8,
                opacity:0.7
            },{
                scale:1,
                opacity:1,
                scrollTrigger:{
                    trigger:publicImgRef.current,
                    start:"top 75%",
                    end: "top 35%",
                    scrub:true,
                },
                ease: Power3.easeInOut
            })
        }
    })

    return(
        <section id="home-projects">
            <div className="home-projects-content-container">
                <Link to='/private' className='project-img-container'>
                    <img ref={privateImgRef} className='home-projects-img private' src={privateImg} alt="" loading='lazy'/>
                    <h3 className="home-projects-txt-mobile">{t("private")}</h3>
                </Link>
                <h3 className="home-projects-txt reversed">{t("private")}</h3>
                <h3 className="home-projects-txt">{t("public")}</h3>
                <Link to='/public' className='project-img-container'>
                    <img ref={publicImgRef} className='home-projects-img public' src={publicImg} alt="" loading='lazy'/>
                    <h3 className="home-projects-txt-mobile">{t("public")}</h3>
                </Link>
            </div>
            { props.anchor ? 
                <a href="#Home">
                    <button className="home-projects-anchor-btn" ><img src={arrow} alt="" /></button>
                </a> : 
                <div/>
            }
        </section>
    )
}

export default HomeProjects;